// Before lambdas
Runnable r1 = new Runnable() {
    @Override
    public void run() {
        System.out.println("Hello");
    }
};

// With lambda
Runnable r2 = () -> System.out.println("Hello");

// Lambda with parameter
Comparator<String> comp = (a, b) -> a.compareTo(b);

// Method reference equivalent
Comparator<String> comp2 = String::compareTo;

Function<String, Integer> strLen = String::length;
Consumer<String> printer = System.out::println;
Supplier<List<String>> listFactory = ArrayList::new;
Predicate<String> isEmpty = String::isEmpty;

// Composing functions
Function<String, String> trim = String::trim;
Function<String, Integer> trimAndCount = trim.andThen(strLen);
System.out.println(trimAndCount.apply("  hello  ")); // 5

List<String> words = List.of("apple", "ant", "banana", "avocado", "blueberry");

// Group by first letter
Map<Character, List<String>> byLetter = words.stream()
    .collect(Collectors.groupingBy(w -> w.charAt(0)));
// {a=[apple, ant, avocado], b=[banana, blueberry]}

// Partition by length
Map<Boolean, List<String>> byLength = words.stream()
    .collect(Collectors.partitioningBy(w -> w.length() > 5));
// {false=[apple, ant], true=[banana, avocado, blueberry]}

// toMap: word -> length
Map<String, Integer> wordLengths = words.stream()
    .collect(Collectors.toMap(w -> w, String::length));

// Creating
Optional<String> present = Optional.of("hello");
Optional<String> empty = Optional.empty();
Optional<String> nullable = Optional.ofNullable(null); // safe

// Consuming
String value = present.orElse("default");
String computed = empty.orElseGet(() -> expensiveDefault());

// Chaining (like a null-safe pipeline)
Optional<Integer> length = Optional.ofNullable(getUserName())
    .map(String::trim)
    .filter(s -> !s.isEmpty())
    .map(String::length);

// Anti-pattern: don't do this
if (optional.isPresent()) { optional.get(); } // defeats the purpose
